def search(filters):
    query = "SELECT * FROM table_name WHERE "

    for filter in filters:
        field = filter['field']
        op = filter['op']
        value = filter['value']

        if op == '=':
            query += f"{field} = '{value}' AND "
        elif op == '>':
            query += f"{field} > {value} AND "
        elif op == '<':
            query += f"{field} < {value} AND "
        elif op == 'LIKE':
            query += f"{field} LIKE '%{value}%' AND "

